import{_ as b,o as e,c as a,j as r,a as t,a1 as d}from"./chunks/framework.Bp7r_-XI.js";const i=JSON.parse('{"title":"陷阱专家","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/陷阱专家.md","filePath":"4.资源分区/6.技艺及称号/杂项/陷阱专家.md"}'),n={name:"4.资源分区/6.技艺及称号/杂项/陷阱专家.md"};function s(o,p,D,l,C,_){return e(),a("div",null,[...p[0]||(p[0]=[r("h1",{id:"陷阱专家",tabindex:"-1"},[t("陷阱专家 "),r("a",{class:"header-anchor",href:"#陷阱专家","aria-label":'Permalink to "陷阱专家"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风024")])])],-1),d('<h1 id="陷阱专家-1" tabindex="-1">陷阱专家 <a class="header-anchor" href="#陷阱专家-1" aria-label="Permalink to &quot;陷阱专家&quot;">​</a></h1><p>陷阱专家-D级称号<br> D+500<br> 人皆曰‘予知’，驱而纳诸罟擭陷阱之中，而莫之知辟也。</p><p>你布置的陷阱DC+1。<br> 开放专业手艺-陷阱，并提升其等级至3。</p><p>开放陷阱专家技能树<br> 开放战地陷阱列表</p><p>陷阱专家技能树</p><p>对灵陷阱专家<br> 750<br> 能捉鬼的不止吸尘器。<br> 你布置的陷阱视为具有【法破】。</p><p>陷阱排除专家<br> D+1500<br> 能拆会装，方为专家。</p><p>在解除装置（不仅限于陷阱）时将陷阱专业作为专业加入DP计算。</p><p>战地陷阱专家<br> C+1000<br> 杀伤！杀伤！杀伤！威力就是战场上的一切！</p><p>你布置的陷阱DC提升&lt;【手艺-陷阱专业】/3&gt;，小数点后进一计算。</p><p>高效制作专家<br> B+2000<br> 天下武功，唯快不破！<br> 什么？你说布置陷阱不算武功？就你话多！</p><p>你在每回合获得4AP，仅能用于陷阱相关的行动。<br> 你的陷阱具有A级先制。</p><p>陷阱材料专家<br> D+500/C+1000/B+2000/A+4000差价升级<br> 工业的基础是能源，机械的基础是材料！</p><p>现在你能用更优质的材料布置你的陷阱。<br> 你布设的陷阱dc增加2/4/8/16。</p><p>陷阱搜索专家<br> D+500/C+1000/B+2000/A+4000差价升级<br> 会踏入陷阱的，不是真正的陷阱专家。</p><p>你会被动的对你感知范围内的陷阱进行侦测对抗。<br> 你在对抗静物（至少1轮没有移动的单位/物品）的侦测对抗中视为具有D/C/B级自然本质侦测能力。<br> 你的侦测检定获得1/2/4/8点附加成功。</p><p>陷阱体验专家<br> C+1000<br> 会踏入陷阱的，不是真正的陷阱专家。<br> 除非他是故意的。</p><p>在你触发可被你精确定位/模糊定位的陷阱时，该陷阱对你的dc下降&lt;【手艺-陷阱专业】/3&gt;，小数点后进一计算。</p><p>陷阱隐蔽专家<br> D+500/C+1000/B+2000/A+4000差价升级<br> -如何保证敌人会踏入陷阱呢？<br> -只要让敌人看不见它就好！</p><p>陷阱获得D/C/B/A级自然本质反侦测。</p><p>陷阱展开专家？-基础陷阱展开技术<br> D+500<br> -如何保证敌人会踏入陷阱呢？<br> -只要触发范围够大就好！<br> -怎么做到的？<br> -问就是拓扑学！</p><p>你布置陷阱时，可以使其基础触发范围和生效范围提升为7.5米半径的圆。</p><p>陷阱展开专家-陷阱扩展技术<br> C+1000/B+2000/A+4000差价升级<br> -如何保证敌人会踏入陷阱呢？<br> -只要触发范围够大就好！<br> -怎么做到的？<br> -问就是量子力学！</p><p>你布置的陷阱触发范围和生效范围圆形半径增加15/30/240米。</p><p>战地陷阱列表</p><p>对于本列表的陷阱，你可以以标准动作在你的触及范围内选择一个位置，铺设你购买的陷阱。当除你以外的任意单位经过时，立即触发。</p><p>迷魂陷阱<br> D+500/C+1000/B+2000/A+4000差价升级<br> 进行DC=11/18/32/49的反射豁免，失败则在当前场景中，在智力、感知、风度属性及专注技能的相关检定上，受到5/5/14/20dp器械减值，成功数减少0/2/2/4。<br> 在A级时额外使被影响的目标受到对于陷阱布置者的迷情效果，A级毒素/药物来源。</p><p>疲劳陷阱<br> D+500/C+1000差价升级<br> 进行DC=12/18的强韧豁免，失败则受到差额的疲乏点数。<br> 在C级时额外使被影响的目标受到3点不可豁免的疲乏点数。<br> 可叠加，同级毒素/药物来源。</p><p>闪光弹陷阱<br> D+500/C+1000差价升级<br> 进行DC=11/19的反射豁免，失败则受到1/3点不可豁免的目眩点数和耳鸣点数。</p><p>纠缠陷阱<br> D+500/C+1000差价升级<br> 进行DC=11/21的反射豁免，失败则受到3/7不可豁免的纠缠点数。</p><p>穿足陷阱<br> D+500/C+1000差价升级<br> 进行DC=8/17的反射豁免，失败则在该场景内移动速度减半。这是高一级创伤来源的困难地形效果。<br> 可以用一个整轮动作，以失败数为dc进行急救检定，成功则移除该效果。<br> D级时，受影响者在移除该效果前，敏捷相关检定受到3dp的器械减值。<br> C级时，替换为受影响者在移除该效果前，所有生理检定受到3dp的器械减值。</p><p>闪光爆陷阱<br> C+1000<br> 进行DC=17的反射豁免，失败则受到2点不可豁免的目眩点数，并且全身被发光粉尘覆盖，从隐形状态显形。若需要对抗则视为一个C级幻像来源的魂牵效果</p><p>陷阱专家工具箱<br> D+500<br> 你可以在战斗之外在陷阱专家工具箱中储存最多12个陷阱。<br> 你可以以标准动作向目标地点发射一个储存的陷阱，射程为90米。<br> 该陷阱视为在目标地点布置，在当前回合结束时完成布置，完成布置之后才会被触发。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',35)])])}const h=b(n,[["render",s]]);export{i as __pageData,h as default};
